"""Router for Permission — generated by BackendAgent."""
from __future__ import annotations

from fastapi import APIRouter, HTTPException

from schemas import PermissionCreate, PermissionUpdate, PermissionResponse
from services import PermissionService

router = APIRouter()
_service = PermissionService()


@router.get("/", response_model=list[PermissionResponse])
def list_permissions() -> list:
    """List all permissions."""
    return _service.list_permissions()


@router.post("/", response_model=PermissionResponse, status_code=201)
def create_permission(data: PermissionCreate) -> object:
    """Create a new permission."""
    try:
        return _service.create_permission(data.model_dump())
    except NotImplementedError:
        raise HTTPException(status_code=501, detail="Not yet implemented")


@router.get("/{id}", response_model=PermissionResponse)
def get_permission(id: str) -> object:
    """Get a single permission by id."""
    item = _service.get_permission(id)
    if item is None:
        raise HTTPException(status_code=404, detail="Permission not found")
    return item


@router.put("/{id}", response_model=PermissionResponse)
def update_permission(id: str, data: PermissionUpdate) -> object:
    """Update an existing permission."""
    try:
        result = _service.update_permission(id, data.model_dump(exclude_unset=True))
    except NotImplementedError:
        raise HTTPException(status_code=501, detail="Not yet implemented")
    if result is None:
        raise HTTPException(status_code=404, detail="Permission not found")
    return result


@router.delete("/{id}", status_code=204)
def delete_permission(id: str) -> None:
    """Delete a permission. Level-3 action — requires permission check."""
    if not _service.delete_permission(id):
        raise HTTPException(status_code=404, detail="Permission not found")
